// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

// Try to guess extension from content-type if filename is missing/incorrect
function extFromContentType(ct = '') {
  const t = String(ct).toLowerCase();
  if (t.includes('pdf')) return '.pdf';
  if (t.includes('msword')) return '.doc';
  if (t.includes('officedocument.wordprocessingml')) return '.docx';
  if (t.includes('text/plain')) return '.txt';
  if (t.includes('text/markdown')) return '.md';
  return '';
}

// Ensure filename has an extension if backend doesn’t provide one
function ensureExtension(filename, contentType) {
  const name = String(filename || '').trim();
  if (!name) return `document${extFromContentType(contentType) || ''}`;
  if (/\.[a-z0-9]{1,6}$/i.test(name)) return name;
  return `${name}${extFromContentType(contentType) || ''}`;
}

/**
 * downloadDocument.php
 * Common PHP pattern in your app:
 * - needs Authorization Bearer <token>
 * - AND accessToken as param/body (like listDocuments.php)
 * - AND documentId
 *
 * Returns: blob
 */
export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  // DEV MOCK
  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'text/plain' });
    return { data: blob, headers: { 'content-type': 'text/plain' } };
  }

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    console.log('📥 downloadDocument request:', {
      url,
      documentId,
      tokenPrefix: String(accessToken).slice(0, 12) + '...',
    });

    // IMPORTANT: send both Authorization AND accessToken (PHP endpoints often require both)
    return axios.post(
      url,
      { documentId, accessToken }, // ✅ fix 400 for many PHP backends
      {
        responseType: 'blob',
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
          Accept: '*/*',
        },
        // extra safety: also send as query param (won't hurt if ignored)
        params: { accessToken },
        validateStatus: (s) => s >= 200 && s < 300, // throw on non-2xx
      }
    );
  });
}

/**
 * Downloads and saves the file using whatever type the backend returns (PDF/DOCX/etc).
 * Does NOT force PDF.
 */
export async function downloadAndSaveDocuments(documentId, filename) {
  const resp = await downloadDocument(documentId);
  const blob = resp?.data;

  const contentType =
    resp?.headers?.['content-type'] ||
    resp?.headers?.['Content-Type'] ||
    '';

  const safeName = ensureExtension(
    filename || `document_${documentId}`,
    contentType
  );

  console.log('✅ downloadDocument success:', {
    documentId,
    filename: safeName,
    contentType,
    bytes: blob?.size,
  });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = safeName;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);
}
